import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, of } from 'rxjs';

//import { Presente, PresenteForm } from '../models';
import { environment } from 'src/environments/environment';
import { Gift, GiftForm } from './gift.model';

// ── Mock data for development without backend ──────────────
const MOCK_PRESENTES: Gift[] = [
  { id: 1,  nome: 'Jogo de Panelas Premium',   descricao: 'Conjunto completo antiaderente para a nossa nova cozinha', valor: 350,  emoji: '🍳', categoria: 'Cozinha',  status: 'DISPONIVEL' },
  { id: 2,  nome: 'Cafeteira Italiana',         descricao: 'Para começar cada manhã juntos com muito café e amor',     valor: 180,  emoji: '☕', categoria: 'Cozinha',  status: 'DISPONIVEL' },
  { id: 3,  nome: 'Jogo de Toalhas Felpudas',  descricao: '6 peças de algodão egípcio 500g/m² — luxo no dia a dia',  valor: 120,  emoji: '🛁', categoria: 'Banheiro', status: 'DISPONIVEL' },
  { id: 4,  nome: 'Aspirador Robô',             descricao: 'Para a casa sempre limpa enquanto aproveitamos a vida',   valor: 650,  emoji: '🤖', categoria: 'Sala',     status: 'DISPONIVEL' },
  { id: 5,  nome: 'Jogo de Cama Queen',         descricao: '400 fios, 100% algodão — noites de sonho garantidas',    valor: 280,  emoji: '🛏️', categoria: 'Quarto',   status: 'DISPONIVEL' },
  { id: 6,  nome: 'Airfryer Digital',           descricao: 'Para receitas saudáveis e saborosas todo dia',            valor: 350,  emoji: '🍟', categoria: 'Cozinha',  status: 'DISPONIVEL' },
  { id: 7,  nome: 'Kit Lua de Mel ✈️',          descricao: 'Contribua para realizarmos a viagem dos nossos sonhos!',  valor: 500,  emoji: '✈️', categoria: 'Viagem',   status: 'DISPONIVEL' },
  { id: 8,  nome: 'Adega Climatizada',          descricao: 'Para os bons momentos e vinhos a dois',                  valor: 800,  emoji: '🍷', categoria: 'Sala',     status: 'DISPONIVEL' },
  { id: 9,  nome: 'Jogo de Jantar 12 Peças',   descricao: 'Porcelana para receber família e amigos com elegância',   valor: 220,  emoji: '🍽️', categoria: 'Cozinha',  status: 'DISPONIVEL' },
  { id: 10, nome: 'Smart TV 55"',               descricao: 'Para nossas noites de filmes no novo lar',               valor: 2200, emoji: '📺', categoria: 'Sala',     status: 'DISPONIVEL' },
  { id: 11, nome: 'Churrasqueira a Gás',        descricao: 'Domingos em família estão garantidos!',                  valor: 900,  emoji: '🥩', categoria: 'Outros',   status: 'DISPONIVEL' },
  { id: 12, nome: 'Espelho Decorativo',         descricao: 'Elegância para o hall de entrada do nosso lar',          valor: 150,  emoji: '🪞', categoria: 'Sala',     status: 'DISPONIVEL' },
  { id: 13, nome: 'Kit Banheiro Completo',      descricao: 'Acessórios dourados para o banheiro dos sonhos',         valor: 260,  emoji: '🪥', categoria: 'Banheiro', status: 'DISPONIVEL' },
  { id: 14, nome: 'Sanduicheira Grill',         descricao: 'Brunch perfeito em qualquer dia da semana',              valor: 130,  emoji: '🥪', categoria: 'Cozinha',  status: 'DISPONIVEL' },
  { id: 15, nome: 'Jogo de Copos Importado',   descricao: 'Cristal austríaco para brindarmos à vida',               valor: 185,  emoji: '🥂', categoria: 'Cozinha',  status: 'DISPONIVEL' },
  { id: 16, nome: 'Luminária de Cabeceira',     descricao: 'Luz certa para as nossas noites de leitura',            valor: 95,   emoji: '🪔', categoria: 'Quarto',   status: 'DISPONIVEL' },
];

@Injectable({ providedIn: 'root' })
export class GiftService {
  private http = inject(HttpClient);
  private readonly api = `${environment.apiUrl}/presentes`;

  // Toggle this to use real API
  private useMock = true;

  listar(): Observable<Gift[]> {
    if (this.useMock) return of([...MOCK_PRESENTES]);
    return this.http.get<Gift[]>(this.api);
  }

  criar(dto: GiftForm): Observable<Gift> {
    if (this.useMock) {
      const novo: Gift = { ...dto, id: Date.now(), status: 'DISPONIVEL' };
      MOCK_PRESENTES.push(novo);
      return of(novo);
    }
    return this.http.post<Gift>(this.api, dto);
  }

  deletar(id: number): Observable<void> {
    if (this.useMock) {
      const i = MOCK_PRESENTES.findIndex(p => p.id === id);
      if (i !== -1) MOCK_PRESENTES.splice(i, 1);
      return of(void 0);
    }
    return this.http.delete<void>(`${this.api}/${id}`);
  }

  marcarReservado(id: number): void {
    const p = MOCK_PRESENTES.find(p => p.id === id);
    if (p) p.status = 'RESERVADO';
  }

  formatCurrency(valor: number): string {
    return valor.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  }
}
